logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET")
OUTPUT_PREFIX = os.environ.get("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")


def process_image_bytes(data: bytes) -> bytes:
    return data


def publish_notification(subject: str, message: dict) -> None:
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not set; skipping notification")
        return

    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject[:100],
        Message=json.dumps(message, default=str),
    )


def handle_s3_record(record: dict) -> dict:
    bucket = record["s3"]["bucket"]["name"]
    key = unquote_plus(record["s3"]["object"]["key"])

    logger.info("Processing object s3://%s/%s", bucket, key)

    response = s3.get_object(Bucket=bucket, Key=key)
    body = response["Body"].read()

    processed = process_image_bytes(body)

    destination_bucket = OUTPUT_BUCKET or bucket
    destination_key = f"{OUTPUT_PREFIX}{key.split('/')[-1]}"

    s3.put_object(
        Bucket=destination_bucket,
        Key=destination_key,
        Body=processed,
        ContentType=response.get("ContentType", "application/octet-stream"),
        Metadata={
            "source-bucket": bucket,
            "source-key": key,
            "processed-by": "lambda-image-processor",
        },
    )

    result = {
        "source_bucket": bucket,
        "source_key": key,
        "destination_bucket": destination_bucket,
        "destination_key": destination_key,
        "status": "processed",
        "size_bytes": len(processed),
    }

    publish_notification(
        subject="Image processed",
        message=result,
    )

    logger.info("Successfully processed %s", json.dumps(result))
    return result


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []
    failures = []

    records = event.get("Records", [])
    if not records:
        message = {
            "status": "no_records",
            "event": event,
        }
        logger.warning("No records found in event")
        return {
            "statusCode": 200,
            "body": json.dumps(message),
        }

    for record in records:
        try:
            if record.get("eventSource") == "aws:s3":
                results.append(handle_s3_record(record))
            else:
                logger.warning("Skipping unsupported record source: %s", record.get("eventSource"))
        except Exception as exc:
            error_info = {
                "error": str(exc),
                "traceback": traceback.format_exc(),
                "record": record,
            }
            failures.append(error_info)
            logger.error("Failed processing record: %s", json.dumps(error_info, default=str))

    summary = {
        "processed_count": len(results),
        "failed_count": len(failures),
        "results": results,
        "failures": failures,
    }

    if failures:
        publish_notification(
            subject="Image processing failures",
            message=summary,
        )
        return {
            "statusCode": 207,
            "body": json.dumps(summary, default=str),
        }

    return {
        "statusCode": 200,
        "body": json.dumps(summary, default=str),
    }